--
-- Table structure for table `orders`
--

DROP TABLE IF EXISTS `orders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `orders` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `order_no` varchar(60) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Mã đơn hàng',
  `user_id` bigint(20) NOT NULL COMMENT 'ID người dùng',
  `lottery_id` bigint(20) NOT NULL COMMENT 'ID loại xổ số',
  `lottery_name` varchar(60) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tên loại xổ số',
  `type_id` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'ID loại cược',
  `play_id` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'ID cách chơi',
  `play_title` varchar(60) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tên cách chơi',
  `expect` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Mã kỳ quay',
  `unit` enum('yuan','jiao','fen','li') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'yuan' COMMENT 'yuan-đồng, jiao-hào, fen-xu, li-ly',
  `bets` int(11) NOT NULL COMMENT 'Số cược',
  `multiple` int(11) NOT NULL DEFAULT '1' COMMENT 'Bội số cược',
  `code` longtext COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Nội dung đặt cược',
  `amount` decimal(18,4) NOT NULL COMMENT 'Số tiền đặt cược',
  `bonus` decimal(18,4) NOT NULL DEFAULT '0.0000' COMMENT 'Số tiền trúng thưởng',
  `status` enum('pending','won','lost','canceled') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending' COMMENT 'pending-chờ xử lý, won-thắng, lost-thua, canceled-đã hủy',
  `placed_at` datetime NOT NULL COMMENT 'Thời gian đặt cược',
  `settled_at` datetime DEFAULT NULL COMMENT 'Thời gian thanh toán',
  `created_at` datetime NOT NULL COMMENT 'Thời gian tạo',
  PRIMARY KEY (`id`),
  UNIQUE KEY `order_no` (`order_no`),
  KEY `idx_user_placed` (`user_id`,`placed_at`),
  KEY `idx_lottery_expect` (`lottery_id`,`expect`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=71 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Bảng đơn cược';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `orders`
--

LOCK TABLES `orders` WRITE;
/*!40000 ALTER TABLE `orders` DISABLE KEYS */;
